VALUES
  ('bookkeeper-moex-01729', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司於 X1 年期末對其當日帳面價值$800,000 之生產設備進行減損測試，經評估該設備之公平價值為 $700,000，出售之直接銷售成本為$150,000，後續期間使用時將產生淨現金流入為$1,200,000（折現值 $780,000），則甲公司當期應認列該設備減損損失之金額為：', '["$0", "$20,000", "$100,000", "$250,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01730', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲、乙、丙三公司於本期以相同溢價價格取得相同數量之上市公司債券，均分類為「以公平價值衡量且 公平價值變動認列為損益之金融資產」，且取得之交易成本均認列為當期費用。惟就溢價部分，甲、乙 公司係分別以利息法與直線法進行攤銷，丙公司則選擇不攤銷。關於該金融資產所有本期會計處理對三 公司本期淨利影響之差異，下列敘述何者正確？', '["甲公司本期淨利最低", "乙公司本期淨利最低", "丙公司本期淨利最低", "甲、乙、丙三公司本期淨利相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01731', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '藍天公司之產品售價每單位為$40，單位生產成本包括直接原料$6、直接人工$7、製造費用$10（其中60% 為固定成本）。該公司最近接獲一筆特殊海外訂單，欲訂購50,000單位產品，所需增加之成本除生產成 本外，另有每單位$5 之運費。若該公司目前有足夠的產能可供生產此訂單，則其願意接受此訂單的最低 售價為：', '["$17", "$22", "$24", "$28"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01732', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '甲公司本期壞帳費用$90，應收帳款資料如下： 期初    期末 應收帳款  $100    $340 備抵壞帳  (70)    (120) $30    $220 甲公司以間接法編製之現金流量表中營業活動部分，因應收帳款與壞帳費用之調整，共計應由淨利減除 之金額為：', '["$190", "$240", "$280", "$330"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01733', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '和平公司採定期盤存制，已知其去年底的存貨高估$15,000，而今年底的存貨又低估$9,000，則今年度的 淨利會因這兩項錯誤而：', '["低估$9,000", "低估$24,000", "高估$6,000", "高估$24,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01734', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '信義公司去年期末存貨金額為$15,000，其中包含下列項目：寄銷在外商品$4,500，在途進貨$5,100（目的 地交貨），承銷他人商品$3,750。則該公司去年期末存貨正確金額為：', '["$6,150", "$10,500", "$11,250", "$15,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01735', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '合歡公司99年度淨利為$20,000，已知當年度曾提列折舊$5,000，另有處分資產利益$3,000，則該年度「 營業活動之現金流量」為：', '["$18,000", "$22,000", "$25,000", "$28,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01736', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '忠孝公司今年初備抵呆帳有貸餘$15,000。今年4/15，公司確定有一筆帳款$10,000無法收回，因而加以沖 銷；但經過公司鍥而不捨的追討，該帳款又得以於今年12/1收回$3,000。今年底公司依應收帳款餘額 （$500,000）的2%估列呆帳。則今年底調整後備抵呆帳的貸餘為：', '["$2,000", "$5,000", "$8,000", "$10,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01737', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '在銀行存款調節表中，「存款不足退票」應作為：', '["公司帳現金餘額的減項", "銀行對帳單餘額的加項", "公司帳現金餘額的加項", "銀行對帳單餘額的減項"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01738', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '四維公司於97年初購入設備：成本$330,000，估計可使用4年，殘值為$30,000，採直線法提列折舊；99年 初發生改良支出$70,000，該支出能使設備之使用年限延長2年（即至102年底），殘值不變。則99年底 該設備應提列折舊為：', '["$75,000", "$61,667", "$55,000", "$37,500"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01739', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '欣欣商店合夥人甲與乙之資本額分別為$200,000及$300,000，今丙想加入合夥，徵得所有合夥人之同意， 向乙購買1/2股權，付現$200,000，則欣欣商店帳冊紀錄上丙合夥人之資本為：', '["$300,000", "$250,000", "$200,000", "$150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01740', 'bookkeeper', 'bookkeeper-moex-100-d35177eb', 'sub-bookkeeper-01', NULL, 'single_choice', '正常餘額為借餘的帳戶包括：', '["資產、費用及股本", "資產、收入及負債", "資產、股利及費用", "收入、負債及股本"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "36c39c55491d", "answer_pdf_sha1": "f7ba25d8d88a", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "會計學概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01741', 'bookkeeper', 'bookkeeper-moex-100-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '32', '["開出未稅價，營業稅外加", "定價應內含營業稅", "對消費者及營業人皆開未稅價", "應視其為專營或兼營之營業人而有不同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "19429a14fc1e", "answer_pdf_sha1": "35bec9c9a383", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
